__global__ void stream_read_unroll4(const float4* __restrict__ in, uint64_t n_vec4, float* __restrict__ sink) {
    uint64_t idx = (uint64_t)blockIdx.x*blockDim.x+threadIdx.x;
    uint64_t stride = (uint64_t)gridDim.x*blockDim.x;
    float4 acc = make_float4(0,0,0,0);
    uint64_t i = idx;
    for (; i + 3*stride < n_vec4; i += 4*stride) {
        float4 v0 = in[i];
        float4 v1 = in[i+stride];
        float4 v2 = in[i+2*stride];
        float4 v3 = in[i+3*stride];
        acc.x += v0.x+v1.x+v2.x+v3.x;
        acc.y += v0.y+v1.y+v2.y+v3.y;
        acc.z += v0.z+v1.z+v2.z+v3.z;
        acc.w += v0.w+v1.w+v2.w+v3.w;
    }
    for (; i < n_vec4; i += stride) {
        float4 v = in[i];
        acc.x+=v.x; acc.y+=v.y; acc.z+=v.z; acc.w+=v.w;
    }
    __shared__ float sx[256],sy[256],sz[256],sw[256];
    int tid=threadIdx.x;
    sx[tid]=acc.x; sy[tid]=acc.y; sz[tid]=acc.z; sw[tid]=acc.w;
    __syncthreads();
    for (int s=blockDim.x/2;s>0;s>>=1){ if(tid<s){sx[tid]+=sx[tid+s];sy[tid]+=sy[tid+s];sz[tid]+=sz[tid+s];sw[tid]+=sw[tid+s];} __syncthreads(); }
    if(tid==0) atomicAdd(&sink[0], sx[0]+sy[0]+sz[0]+sw[0]);
}

static double median(std::vector<double> v){ std::sort(v.begin(),v.end()); size_t n=v.size(); return n%2? v[n/2] : 0.5*(v[n/2-1]+v[n/2]); }

int main(int argc, char**argv){
    uint64_t buffer_bytes = (argc>1)? strtoull(argv[1],0,10) : 3ull*1024*1024*1024;
    int blocks = (argc>2)? atoi(argv[2]) : 8192;
    int threads = (argc>3)? atoi(argv[3]) : 256;
    uint64_t n_vec4 = buffer_bytes/16;
    buffer_bytes = n_vec4*16;
    HIP_CHECK(hipSetDevice(0));
    float4* d_buf; float* d_sink;
    HIP_CHECK(hipMalloc(&d_buf, buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, sizeof(float)));
    HIP_CHECK(hipMemset(d_buf,1,buffer_bytes));
    HIP_CHECK(hipMemset(d_sink,0,sizeof(float)));
    hipEvent_t start,stop; HIP_CHECK(hipEventCreate(&start)); HIP_CHECK(hipEventCreate(&stop));
    for(int i=0;i<5;i++) stream_read_unroll4<<<blocks,threads>>>(d_buf,n_vec4,d_sink);
    HIP_CHECK(hipDeviceSynchronize());
    std::vector<double> times;
    for(int i=0;i<30;i++){
        HIP_CHECK(hipEventRecord(start));
